import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  CronListSchema,
  CronSaveMetadataSchema,
  CronUpdateJobSchema,
  CronToggleJobSchema,
  CronDeleteJobSchema,
  CronAddJobSchema,
  CronGetLogsSchema,
  CronClearLogsSchema,
  CronGetLogInfoSchema,
  CronWrapCommandSchema,
  ApiResult,
  CronJob,
} from './types';
import { cronService } from '../services/CronService';
import { cronLogService, CronLogInfo, CronLogContent } from '../services/CronLogService';

export function registerCronHandlers() {
  ipcMain.handle(IPC_CHANNELS.CRON_LIST, async (_event, input): Promise<ApiResult<CronJob[]>> => {
    try {
      const config = CronListSchema.parse(input);
      const jobs = await cronService.list(config.serverId);
      return { success: true, data: jobs };
    } catch (error) {
      console.error('Error listing cron jobs:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_SAVE_METADATA, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const config = CronSaveMetadataSchema.parse(input);
      cronService.saveMetadata(config.serverId, config.jobSignature, config.cronId, config.name, config.description, config.type, config.createdBy);
      return { success: true };
    } catch (error) {
      console.error('Error saving cron metadata:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_UPDATE_JOB, async (_event, input): Promise<ApiResult<{ jobSignature: string }>> => {
    try {
      const config = CronUpdateJobSchema.parse(input);
      const result = await cronService.updateJob(config);
      return { success: true, data: result };
    } catch (error) {
      console.error('Error updating cron job:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_TOGGLE_JOB, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const config = CronToggleJobSchema.parse(input);
      await cronService.toggleJob(config);
      return { success: true };
    } catch (error) {
      console.error('Error toggling cron job:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_DELETE_JOB, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const config = CronDeleteJobSchema.parse(input);
      await cronService.deleteJob(config);
      return { success: true };
    } catch (error) {
      console.error('Error deleting cron job:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_ADD_JOB, async (_event, input): Promise<ApiResult<{ jobSignature: string; cronId: string }>> => {
    try {
      const config = CronAddJobSchema.parse(input);
      const result = await cronService.addJob(config);
      return { success: true, data: result };
    } catch (error) {
      console.error('Error adding cron job:', error);
      return { success: false, error: String(error) };
    }
  });

  // Cron log handlers
  ipcMain.handle(IPC_CHANNELS.CRON_GET_LOGS, async (_event, input): Promise<ApiResult<CronLogContent>> => {
    try {
      const config = CronGetLogsSchema.parse(input);
      const logs = await cronLogService.getLogs(config.serverId, config.cronId, {
        tailLines: config.tailLines,
      });
      return { success: true, data: logs };
    } catch (error) {
      console.error('Error getting cron logs:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_CLEAR_LOGS, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const config = CronClearLogsSchema.parse(input);
      await cronLogService.clearLogs(config.serverId, config.cronId);
      return { success: true };
    } catch (error) {
      console.error('Error clearing cron logs:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_GET_LOG_INFO, async (_event, input): Promise<ApiResult<CronLogInfo>> => {
    try {
      const config = CronGetLogInfoSchema.parse(input);
      const info = await cronLogService.getLogInfo(config.serverId, config.cronId);
      return { success: true, data: info };
    } catch (error) {
      console.error('Error getting cron log info:', error);
      return { success: false, error: String(error) };
    }
  });

  ipcMain.handle(IPC_CHANNELS.CRON_WRAP_COMMAND, async (_event, input): Promise<ApiResult<string>> => {
    try {
      const config = CronWrapCommandSchema.parse(input);
      const wrappedCommand = cronLogService.wrapCommandWithLogging(
        config.command,
        config.cronId,
        {
          maxSizeBytes: config.maxSizeBytes,
          maxLines: config.maxLines,
          backupCount: config.backupCount,
        }
      );
      return { success: true, data: wrappedCommand };
    } catch (error) {
      console.error('Error wrapping cron command:', error);
      return { success: false, error: String(error) };
    }
  });
}
